class TestListProcesses:
    def test_empty(self, client) -> None:
        resp = client.get("/api/v2/processes")
        assert resp.status_code == 200
        assert resp.json() == []

    def test_lists_processes(self, client, db) -> None:
        _seed_hook(db, session_id="s1", pid=10, received_at=100.0)
        _seed_statusline(db, session_id="s1", pid=10, cost_usd=2.5, received_at=110.0)
        _seed_hook(db, session_id="s2", pid=20, received_at=200.0)

        resp = client.get("/api/v2/processes")
        assert resp.status_code == 200
        body = resp.json()
        assert len(body) == 2
        # Sorted DESC by last_activity_at — pid=20 first
        assert body[0]["pid"] == 20
        assert body[1]["pid"] == 10
        # No sessions[] on list response
        assert body[0].get("sessions") is None

    def test_filter_source_system(self, client, db) -> None:
        _seed_hook(db, session_id="s1", pid=10, source_system="a", received_at=100.0)
        _seed_hook(db, session_id="s2", pid=20, source_system="b", received_at=110.0)

        resp = client.get("/api/v2/processes?source_system=b")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["source_system"] == "b"

    def test_filter_cwd(self, client, db) -> None:
        _seed_hook(db, session_id="s1", pid=10, cwd="/a", received_at=100.0)
        _seed_hook(db, session_id="s2", pid=20, cwd="/b", received_at=110.0)

        resp = client.get("/api/v2/processes?cwd=/b")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["cwd"] == "/b"

    def test_filter_since(self, client, db) -> None:
        _seed_hook(db, session_id="s1", pid=10, received_at=100.0)
        _seed_hook(db, session_id="s2", pid=20, received_at=200.0)

        resp = client.get("/api/v2/processes?since=150")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["pid"] == 20


class TestProcessDetail:
    def test_returns_with_sessions_nested(self, client, db) -> None:
        _seed_hook(db, session_id="sa", pid=10, received_at=100.0)
        _seed_hook(db, session_id="sb", pid=10, received_at=200.0)

        resp = client.get("/api/v2/processes")
        process_id = resp.json()[0]["process_id"]

        detail = client.get(f"/api/v2/processes/{process_id}")
        assert detail.status_code == 200
        body = detail.json()
        assert body["process_id"] == process_id
        assert len(body["sessions"]) == 2

    def test_unknown_process_id_404(self, client) -> None:
        resp = client.get("/api/v2/processes/0000000000000000")
        assert resp.status_code == 404


class TestListSessions:
    def test_empty(self, client) -> None:
        resp = client.get("/api/v2/sessions")
        assert resp.status_code == 200
        assert resp.json() == []

    def test_lists_sessions(self, client, db) -> None:
        _seed_hook(db, session_id="sa", pid=10, received_at=100.0)
        _seed_hook(db, session_id="sb", pid=20, received_at=200.0)

        resp = client.get("/api/v2/sessions")
        body = resp.json()
        assert len(body) == 2
        assert body[0]["session_id"] == "sb"  # latest first

    def test_active_filter_excludes_ended(self, client, db) -> None:
        _seed_hook(db, session_id="sa", pid=10, received_at=100.0)
        _seed_hook(
            db, session_id="sb", pid=20, event_name="SessionEnd", received_at=200.0
        )

        resp = client.get("/api/v2/sessions?active=true")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["session_id"] == "sa"

    def test_filter_by_process_id(self, client, db) -> None:
        _seed_hook(db, session_id="sa", pid=10, received_at=100.0)
        _seed_hook(db, session_id="sb", pid=20, received_at=110.0)

        procs = client.get("/api/v2/processes").json()
        target_pid = procs[0]["process_id"]

        resp = client.get(f"/api/v2/sessions?process_id={target_pid}")
        body = resp.json()
        assert len(body) == 1


