class TestLogHooksEndpoint:
    def test_returns_rows_with_derived_ids(self, client, db) -> None:
        _seed_hook(db, session_id="s1", pid=10, received_at=100.0)
        _seed_hook(db, session_id="s1", pid=10, received_at=200.0)

        resp = client.get("/api/v2/log/hooks")
        assert resp.status_code == 200
        body = resp.json()
        assert len(body) == 2
        # Both rows in the same process → same process_id
        assert body[0]["process_id"] == body[1]["process_id"]
        assert body[0]["epoch_id"] == body[1]["epoch_id"]
        # raw_payload included by default
        assert body[0]["raw_payload"] is not None

    def test_filter_session_id(self, client, db) -> None:
        _seed_hook(db, session_id="s1", pid=10, received_at=100.0)
        _seed_hook(db, session_id="s2", pid=20, received_at=110.0)
        resp = client.get("/api/v2/log/hooks?session_id=s2")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["session_id"] == "s2"

    def test_pagination(self, client, db) -> None:
        for t in (100.0, 110.0, 120.0):
            _seed_hook(db, session_id="s1", pid=10, received_at=t)
        resp = client.get("/api/v2/log/hooks?limit=1&offset=1")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["received_at"] == 110.0

    def test_invalid_limit_returns_422(self, client) -> None:
        resp = client.get("/api/v2/log/hooks?limit=2000")
        assert resp.status_code == 422


